import { Injectable } from '@angular/core';
import {
  Resolve,
  ActivatedRouteSnapshot,
  RouterStateSnapshot
} from '@angular/router';

import { UnitmasterService } from './unitmaster.service';

@Injectable({ providedIn: 'root' })
export class UnitmasterResolverService implements Resolve<any[]> {
  constructor(
    private superCategoryService: UnitmasterService
  ) {}

  resolve(route: ActivatedRouteSnapshot, state: RouterStateSnapshot) {
    const unitmaster = this.superCategoryService.getUnitmaster();
    if (unitmaster.length === 0) {
      return this.superCategoryService.getAllUnitmaster();
    } else {
      return unitmaster;
    }
  }
}
