import { Injectable } from '@angular/core';
import {
  Resolve,
  ActivatedRouteSnapshot,
  RouterStateSnapshot
} from '@angular/router';

import { SuperCategoryService } from './supercategory.service';

@Injectable({ providedIn: 'root' })
export class SupercategoryResolverService implements Resolve<any[]> {
  constructor(
    private superCategoryService: SuperCategoryService
  ) {}

  resolve(route: ActivatedRouteSnapshot, state: RouterStateSnapshot) {
    const supercategories = this.superCategoryService.getSuperCategories();
    if (supercategories.length === 0) {
      return this.superCategoryService.getAllSuperCategories();
    } else {
      return supercategories;
    }
  }
}
